#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define PI 3.1415926535897932
#define M INT_MAX
#define A 1103515245
#define C 12345

inline double roundDouble(double value) {
    int newValue = (int)(value);
    if (value - newValue < 0.5)
        return (double)newValue;
    else
        return (double)(newValue++);
}

inline double randu(__global int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(((double)seed[index]) / ((double)M));
}

inline double randn(__global int *seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2.0 * PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

inline int findIndex(__global double *CDF, int lengthCDF, double value) {
    int index = -1;
    for (int x = 0; x < lengthCDF; x++) {
        if (CDF[x] >= value) {
            index = x;
            break;
        }
    }
    if (index == -1) {
        return lengthCDF - 1;
    }
    return index;
}

__kernel void likelihood_kernel(__global double *arrayX,
                                __global double *arrayY,
                                __global double *xj,
                                __global double *yj,
                                __global double *CDF,
                                __global int *ind,
                                __global int *objxy,
                                __global double *likelihood,
                                __global unsigned char *I,
                                __global double *u,
                                __global double *weights,
                                int Nparticles,
                                int countOnes,
                                int max_size,
                                int k,
                                int IszY,
                                int Nfr,
                                __global int *seed,
                                __global double *partial_sums,
                                __local double *buffer) {
    int gid = get_global_id(0);
    int lid = get_local_id(0);
    int group = get_group_id(0);
    int lsize = get_local_size(0);

    double local_weight = 0.0;

    if (gid < Nparticles) {
        double ax = xj[gid];
        double ay = yj[gid];

        ax += 1.0 + 5.0 * randn(seed, gid);
        ay += -2.0 + 2.0 * randn(seed, gid);

        arrayX[gid] = ax;
        arrayY[gid] = ay;

        double like = 0.0;
        int base = gid * countOnes;

        for (int y = 0; y < countOnes; y++) {
            int indX = (int)roundDouble(ax) + objxy[y * 2 + 1];
            int indY = (int)roundDouble(ay) + objxy[y * 2];
            int idx = abs(indX * IszY * Nfr + indY * Nfr + k);
            if (idx >= max_size)
                idx = 0;
            ind[base + y] = idx;

            double val = (double)I[idx];
            like += (((val - 100.0) * (val - 100.0)) -
                     ((val - 228.0) * (val - 228.0))) / 50.0;
        }

        like = like / ((double)countOnes);
        likelihood[gid] = like;

        local_weight = weights[gid] * exp(like);
        weights[gid] = local_weight;
    }

    buffer[lid] = local_weight;
    barrier(CLK_LOCAL_MEM_FENCE);

    for (int offset = lsize >> 1; offset > 0; offset >>= 1) {
        if (lid < offset) {
            buffer[lid] += buffer[lid + offset];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (lid == 0) {
        partial_sums[group] = buffer[0];
    }

    (void)CDF;
    (void)u;
}

__kernel void sum_kernel(__global double *partial_sums, int Nparticles) {
    int gid = get_global_id(0);
    if (gid == 0) {
        int groups = get_num_groups(0);
        double sum = 0.0;
        for (int i = 0; i < groups; i++) {
            sum += partial_sums[i];
        }
        partial_sums[0] = sum;
    }
    (void)Nparticles;
}

__kernel void normalize_weights_kernel(__global double *weights,
                                       int Nparticles,
                                       __global double *partial_sums,
                                       __global double *CDF,
                                       __global double *u,
                                       __global int *seed) {
    int gid = get_global_id(0);
    if (gid == 0) {
        double sumWeights = partial_sums[0];

        for (int i = 0; i < Nparticles; i++) {
            weights[i] = weights[i] / sumWeights;
        }

        CDF[0] = weights[0];
        for (int i = 1; i < Nparticles; i++) {
            CDF[i] = weights[i] + CDF[i - 1];
        }

        double u1 = (1.0 / ((double)Nparticles)) * randu(seed, 0);
        for (int i = 0; i < Nparticles; i++) {
            u[i] = u1 + i / ((double)Nparticles);
        }
    }
}

__kernel void find_index_kernel(__global double *arrayX,
                                __global double *arrayY,
                                __global double *CDF,
                                __global double *u,
                                __global double *xj,
                                __global double *yj,
                                __global double *weights,
                                int Nparticles) {
    int gid = get_global_id(0);

    if (gid < Nparticles) {
        int i = findIndex(CDF, Nparticles, u[gid]);
        if (i == -1)
            i = Nparticles - 1;
        xj[gid] = arrayX[i];
        yj[gid] = arrayY[i];
        weights[gid] = 1.0 / ((double)Nparticles);
    }
}

